// src/pages/ngo/user/MyFundsPage.jsx
import { useState } from "react";
import { useToast } from "../../../context/ToastContext";
import PageHeader   from "../../../components/shared/PageHeader";
import Badge        from "../../../components/shared/Badge";
import { funds }    from "../../../data/mockData";

const fmt = (n) => n?.toLocaleString() ?? "–";

export default function MyFundsPage() {
  const toast = useToast();
  const [myFunds, setMyFunds] = useState(funds.filter((f) => f.ngo === "NGO001"));

  const closeFund = (id) => {
    setMyFunds((fs) => fs.map((f) => f.id === id ? { ...f, status:"closed" } : f));
    toast("Fund closed on ledger", "info");
  };

  return (
    <div>
      <PageHeader title="My Funds" desc="Manage your NGO's fundraising campaigns" />
      <div className="section-gap">
        {myFunds.map((f) => {
          const pct = Math.round((f.raised / f.target) * 100);
          return (
            <div key={f.id} className="card">
              <div style={{ display:"flex", alignItems:"flex-start", justifyContent:"space-between", gap:12, marginBottom:14, flexWrap:"wrap" }}>
                <div>
                  <div style={{ fontSize:15, fontWeight:700, marginBottom:6 }}>{f.name}</div>
                  <div style={{ display:"flex", gap:8, flexWrap:"wrap" }}>
                    <Badge type="teal">{f.id}</Badge>
                    <Badge type={f.status==="open"?"green":"red"}>{f.status}</Badge>
                    <span className="text-dim">Created {f.created}</span>
                  </div>
                </div>
                {f.status === "open" && (
                  <button className="btn btn-danger btn-sm" onClick={() => closeFund(f.id)}>Close Fund</button>
                )}
              </div>

              <div style={{ display:"grid", gridTemplateColumns:"repeat(3,1fr)", gap:10, marginBottom:14 }}>
                {[["Target",`${fmt(f.target)} ◈`],["Raised",`${fmt(f.raised)} ◈`],["Donors",f.donors]].map(([k,v]) => (
                  <div key={k} style={{ background:"var(--bg-surface)", borderRadius:"var(--radius)", padding:"10px 12px" }}>
                    <div style={{ fontSize:10, color:"var(--text-3)", fontFamily:"'DM Mono',monospace", textTransform:"uppercase", letterSpacing:1, marginBottom:4 }}>{k}</div>
                    <div style={{ fontSize:15, fontWeight:700, color:"var(--gold)" }}>{v}</div>
                  </div>
                ))}
              </div>

              <div className="progress-track"><div className="progress-fill" style={{ width:`${pct}%` }} /></div>
              <div style={{ fontSize:11, color:"var(--gold)", marginTop:4, fontFamily:"'DM Mono',monospace" }}>{pct}% of target</div>
            </div>
          );
        })}
      </div>
    </div>
  );
}
